// 1. 拿到 MySQL 的第一行样例数据及所有列名
const mysqlRecord = $('获取MySQL字段列表').first().json;
const mysqlFields = Object.keys(mysqlRecord);

// 2. 拿到飞书现有的所有字段名
const feishuFields = $('获取飞书字段列表').first().json.data.items.map(f => f.field_name);

// 3. ✨ 核心引擎：智能推断飞书字段类型
function guessFeishuType(value) {
  if (value === null || value === undefined) return 1; // 空值兜底：建为多行文本 (Type 1)

  // 判断是否为数字 (并且排除掉像达人UID这种超长数字，长数字依然建为文本防丢失)
  if (typeof value === 'number') return 2; // 数字 (Type 2)
  if (typeof value === 'string' && !isNaN(value) && value.trim() !== '' && value.length < 15 && !(value.startsWith('0') && value.length > 1 && !value.includes('.'))) {
      return 2; 
  }

  // 判断是否为日期 (匹配 YYYY-MM-DD HH:MM:SS 或 YYYY/MM/DD)
  if (typeof value === 'string' && /^\d{4}[-/]\d{2}[-/]\d{2}/.test(value)) {
      return 5; // 日期 (Type 5)
  }

  return 1; // 其他所有情况，统统建为多行文本 (Type 1)
}

// 4. 找出缺失的字段，并附带计算好的类型
const missingFields = [];
for (const field of mysqlFields) {
  if (!feishuFields.includes(field)) {
    missingFields.push({
      field_name: field,
      type: guessFeishuType(mysqlRecord[field])
    });
  }
}

// 5. 输出结果保持原有外层结构，方便后面的 If 节点判断 count
return {
  json: {
    missingFields: missingFields,
    count: missingFields.length
  }
};

try {
  const allInputItems = $input.all();

  // 动态获取主键
  const uniqueKey = $('同步参数配置').first().json.unique_key; 
  if (!uniqueKey) {
    throw new Error('未获取到唯一键配置');
  }

  let keyToRecordId = {};
  const dbRecords = [];

  // 1. ✨ 智能分拣：精准识别你的“飞书数据汇总包”
  for (const item of allInputItems) {
    const data = item.json;
    // 依靠你上一个节点的特征，认出谁是飞书的汇总字典
    if (data.key_to_record_id) {
      keyToRecordId = data.key_to_record_id;
    } else if (!data.feishu_records && !data.message) {
      // 剩下的、且不是飞书汇总包的，就是真实的数据库记录
      dbRecords.push(data);
    }
  }

  const toCreate = [];
  const toUpdate = [];

  // 2. 遍历数据库数据进行比对
  for (const dbRecord of dbRecords) {
    const primaryKeyValue = dbRecord[uniqueKey];

    if (primaryKeyValue === undefined || primaryKeyValue === null || primaryKeyValue === '') {
      continue; 
    }

    // 通过你的字典，瞬间找到对应的 record_id
    const recordId = keyToRecordId[String(primaryKeyValue)];

    // 过滤空值
    const cleanFields = {};
    for (const key of Object.keys(dbRecord)) {
      const val = dbRecord[key];
      if (val !== null && val !== undefined && val !== '' && String(val).trim() !== '') {
        cleanFields[key] = val;
      }
    }

    if (Object.keys(cleanFields).length > 0) {
      if (recordId) {
        // ✨ 找到了！装入更新篮子，附带 record_id
        toUpdate.push({
          record_id: recordId, 
          fields: cleanFields
        });
      } else {
        // 没找到，装入新增篮子
        toCreate.push({
          fields: cleanFields
        });
      }
    }
  }

  return [{ 
    json: {
      toCreate: toCreate,
      toUpdate: toUpdate,
      create_count: toCreate.length,
      update_count: toUpdate.length,
      message: `✅ 匹配成功 | 数据库: ${dbRecords.length} | 飞书字典映射: ${Object.keys(keyToRecordId).length} | 待新增: ${toCreate.length} | 待更新: ${toUpdate.length}`
    } 
  }];

} catch (error) {
  console.error('节点执行错误:', error);
  return [{ json: { _error: true, message: error.message || String(error), node: '对比分类（新增vs更新）' } }];
}

try {
  const data = $input.first().json;
  const toUpdate = data.toUpdate || data.to_update || [];

  if (toUpdate.length === 0) {
    console.log("没有需要更新的记录，分支已安全终止。");
    return []; 
  }

  // 1. ✨ 核心优化：获取飞书官方字段类型字典 (绝对精准，不靠猜)
  // 确保这里的节点名称和你的真实节点名称完全一致
  const schemaItems = $('获取飞书字段列表').first().json.data.items || [];
  const fieldTypeMap = {};
  for (const item of schemaItems) {
    // 飞书的 type 是数字编号，比如 1:多行文本, 2:数字, 5:日期
    fieldTypeMap[item.field_name] = item.type;
  }

  // 2. 严格按飞书标准格式化数据
  const formattedRecords = toUpdate.map(record => {
    const cleanFields = {};

    for (const [key, value] of Object.entries(record.fields)) {
      // 过滤无效空值
      if (value === null || value === undefined || String(value).trim() === '') {
        continue; 
      }

      const expectedType = fieldTypeMap[key];
      let finalValue = value;

      // 3. ✨ 核心转换逻辑：根据飞书要求的类型，对症下药
      switch (expectedType) {
        case 1: // 文本类型 (Text)
          finalValue = String(value);
          break;

        case 2: // 数字类型 (Number)
          finalValue = Number(value);
          if (isNaN(finalValue)) continue; // 如果转换出 NaN，直接跳过保护飞书
          break;

        case 5: // 日期类型 (DateTime) - 飞书的“大坑”
          // 将各种乱七八糟的 MySQL 时间转成标准的 13 位毫秒时间戳
          const dateObj = new Date(value);
          if (!isNaN(dateObj.getTime())) {
             finalValue = dateObj.getTime(); 
          } else {
             continue; // 如果日期解析彻底失败，跳过该字段
          }
          break;

        // 如果你有其他特殊类型（比如 7:复选框），可以继续在这里加 case
        default:
          finalValue = value; // 没匹配上的兜底保持原样
      }

      cleanFields[key] = finalValue;
    }

    // 组装最终更新记录（必须带 record_id）
    return {
      record_id: record.record_id,
      fields: cleanFields
    };
  });

  return [{ json: { records: formattedRecords } }];

} catch (error) {
  console.error('节点执行错误:', error);
  return [{ json: { _error: true, message: error.message || String(error), node: '格式化更新数据' } }];
}

