try {
  const allFeishuRecords = [];

  const uniqueKeyName = $('同步参数配置').first().json.unique_key;
  if (!uniqueKeyName) {
    throw new Error('未获取到唯一键配置');
  }

  // ✨ 核心修复：突破 n8n 分页限制，捞取所有循环批次的数据！
  let runIndex = 0;
  while (true) {
    try {
      // ⚠️ 非常重要：请确保下方的 '飞书多维表查询' 和你的查询节点名字【一字不差】
      // .all(0, runIndex) 的意思是：获取该节点第 0 个分支，第 runIndex 次运行的数据
      const itemsOfThisRun = $('飞书多维表查询').all(0, runIndex); 

      if (!itemsOfThisRun || itemsOfThisRun.length === 0) {
        break; // 如果该页没数据了，说明循环跑完了，退出
      }

      for (const item of itemsOfThisRun) {
        if (item.json && item.json.data && item.json.data.items) {
          const items = item.json.data.items;
          for (const record of items) {
            if (record && record.record_id) {
              const fields = record.fields || {};

              // 智能剥壳处理
              let rawValue = fields[uniqueKeyName];
              let finalKeyValue = null;

              if (rawValue !== undefined && rawValue !== null) {
                if (Array.isArray(rawValue) && rawValue.length > 0) {
                  finalKeyValue = rawValue[0].text || rawValue[0].id || rawValue[0].name || String(rawValue[0]);
                } else if (typeof rawValue === 'object') {
                  finalKeyValue = rawValue.text || rawValue.id || rawValue.name || String(rawValue);
                } else {
                  finalKeyValue = rawValue;
                }
              }

              if (finalKeyValue !== undefined && finalKeyValue !== null && String(finalKeyValue).trim() !== '') {
                allFeishuRecords.push({
                  record_id: record.record_id,
                  fields: fields,
                  primary_key: String(finalKeyValue).trim()
                });
              }
            }
          }
        }
      }
      runIndex++; // 继续去挖下一页的数据！
    } catch (e) {
      break; // 越界报错说明到底了，安全退出
    }
  }

  // 构建主键到 record_id 的映射
  const keyToRecordId = {};
  for (const record of allFeishuRecords) {
    if (record.primary_key) {
      keyToRecordId[record.primary_key] = record.record_id;
    }
  }

  return [{ json: { 
    feishu_records: allFeishuRecords,
    key_to_record_id: keyToRecordId,
    total_count: allFeishuRecords.length,
    message: `✅ 突破分页！共挖掘了 ${runIndex} 页数据，提取 ${allFeishuRecords.length} 条记录，映射 ${Object.keys(keyToRecordId).length} 个唯一键。`
  } }];

} catch (error) {
  console.error('节点执行错误:', error);
  return [{ json: { _error: true, message: error.message || String(error), node: '收集所有飞书记录' } }];
}

try {
  // 跨节点提取我们在中间计算好的完美统计量
  // ⚠️ 注意：这里的名字必须和你实际的对比节点名字一字不差
  const stats = $('对比分类（新增vs更新）').first().json || {};
  const config = $('同步参数配置').first().json || {};

  return [{
    json: {
      result: "success",
      table_id: config.table_id || "unknown",
      create_count: stats.create_count || 0,
      update_count: stats.update_count || 0,
      db_total: stats.total_db_records || 0,
      feishu_total: stats.feishu_total || 0,
      message: `✅ 同步完成 | 目标表: ${config.table_id} | 新增: ${stats.create_count || 0} | 更新: ${stats.update_count || 0}`
    }
  }];
} catch (error) {
  // 就算这里写错，也不影响大局，给个兜底
  return [{ json: { result: "success", message: "同步完成，但战报生成失败" } }];
}
